import{_ as n,o as t,c as r,an as i}from"./chunks/framework.D5fFzH9V.js";const m=JSON.parse('{"title":"Pricing","description":"Preisgestaltung für Pentests inkl. Tagsatz, Richtwerte, Rabatte und Partnerhinweise.","frontmatter":{"description":"Preisgestaltung für Pentests inkl. Tagsatz, Richtwerte, Rabatte und Partnerhinweise."},"headers":[],"relativePath":"de/pricing.md","filePath":"de/pricing.md"}'),a={name:"de/pricing.md"};function s(o,e,d,h,l,u){return t(),r("div",null,[...e[0]||(e[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /de/pricing.md for this page in Markdown format</div><h1 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h1><p>Wenn ein echter Angreifer mehr Zeit aufwendet als ein Pentester, könnte er Sicherheitslücken finden, die der Tester zuvor nicht gefunden hat. Das ist das Timebox-Prinzip.</p><p>Deshalb werden (seriöse) Pentests immer nach zeitlichem Aufwand (meist in Personentagen) verrechnet. Ein Personentag kostet bei uns € 1.600,-. Ab 20 Personentagen geben wir 15% Rabatt (€ 1.360,-).</p><h2 id="und-was-kostet-ein-pentest-jetzt-wirklich" tabindex="-1">Und was kostet ein Pentest jetzt wirklich? <a class="header-anchor" href="#und-was-kostet-ein-pentest-jetzt-wirklich" aria-label="Permalink to &quot;Und was kostet ein Pentest jetzt wirklich?&quot;">​</a></h2><p>Den Aufwand für einen Test schätzen wir vorab in einem Scoping-Termin (mehr Informationen dazu findet ihr unter <a href="./vor-pentests">Vor dem Pentest</a>). Hier sind ein paar Orientierungshilfen, womit ihr in der Regel rechnen könnt.</p><ul><li><strong>Webanwendung</strong>: € 5.000-16.000</li><li><strong>Microsoft Active Directory</strong>: € 12.000-20.000</li><li><strong>Externe Infrastruktur</strong>: € 8.000-11.000</li></ul><h2 id="rabatte" tabindex="-1">Rabatte <a class="header-anchor" href="#rabatte" aria-label="Permalink to &quot;Rabatte&quot;">​</a></h2><ul><li>Ab 20 Personentagen geben wir 15% Rabatt.</li><li>Im Academia-Bereich bieten wir einen sehr attraktiven Tagsatz von € 1.200,-.</li><li>Wir starten aktuell ein <a href="./pro-bono-pentests">Pro Bono-Programm</a>.</li></ul><p>Ansonsten bitten wir um Verständnis, dass wir keine Rabatte gewähren. Das Verhandlungstalent soll nicht preisbestimmend sein. Im Gegenzug könnt ihr von uns volle Fairness und Transparenz erwarten.</p><h2 id="partner" tabindex="-1">Partner <a class="header-anchor" href="#partner" aria-label="Permalink to &quot;Partner&quot;">​</a></h2><p>Wenn wir eine Leistung einmal nicht anbieten können, empfehlen wir gerne kompetente Unternehmen weiter. So freuen wir uns auch, wenn wir von anderen empfohlen werden.</p><p>Wir verrechnen für Weiterempfehlungen <strong>niemals</strong> eine Recommendation-Fee, oder eine sonstige Gebühr. Genauso bezahlen wir auch keine Gebühren für Weiterempfehlungen. Damit basieren unsere Weiterempfehlungen immer auf der Qualität der empfohlenen Firma und nicht auf der Gebühr.</p><p>Schließt ein Security-Unternehmen einen Vertrag direkt mit dem Endkunden und beauftragt uns als Subunternehmer, verrechnen wir 85% vom Endkundenpreis, zumindest jedoch einen Tagsatz von € 1000,-. Unser Partner ist dann dafür verantwortlich, die Bestimmungen aus unserer <a href="/de/servicebeschreibung">Servicebeschreibung</a> an den Endkunden zu überbinden.</p>',14)])])}const g=n(a,[["render",s]]);export{m as __pageData,g as default};
